    char character;
    for (i = 0; str[i] != '\0'; i++)
    {
        character = tolower(str[i]);
        if (character == 'a' || character == 'e' || character == 'i' || character == 'o' || character == 'u')
        {
            vowel++;
        }
    }
    return vowel;
}

void reverse(char str[])
{
    int len = strlen(str);
    char result[len + 1];
    char *start = result;
    char *end = result + len - 1;
    char temp;

    result[0] = '\0';
    strcat(result, str);

    while (start < end)
    {
        temp = *start;
        *start = *end;
        *end = temp;
        start++;
        end--;
    }
    printf("%s\n", result);
}

