    int **r = (int **)malloc(rows * sizeof(int *));
    for (i = 0; i < rows; i++)
    {
        r[i] = (int *)malloc(cols * sizeof(int));
        for (j = 0; j < cols; j++)
        {
            r[i][j] = a[i][j] + b[i][j];
        }
