void product(int **a, int **b, int rows_a, int cols_b, int common)
{
    int i, x, y, z, temp;

    int **r = (int **)malloc(rows_a * sizeof(int *));
    for (i = 0; i < rows_a; i++)
    {
        r[i] = (int *)malloc(cols_b * sizeof(int));
    }

    for (x = 0; x < rows_a; x++)
    {
        for (y = 0; y < cols_b; y++)
        {
            temp = 0;
            for (z = 0; z < common; z++)
            {
                temp += a[x][z] * b[z][y];
            }
            r[x][y] = temp;
        }
    }
    display(r, rows_a, cols_b);
    clear(r, rows_a);
}

