        // Find spaces to get subsequent parts
        for (j = 0; j < len; j++)
        {
            if (names[i][j] == ' ')
            {
                space_count++;
                if (space_count == 1) // Found start of Middle name
                {
                    abbr[k++] = names[i][j+1];
                    abbr[k++] = '.';
                    abbr[k++] = ' ';
                }
                else if (space_count == 2) // Found start of Last name
                {
                    // Copy the rest of the last name
                    int m = j + 1;
                    while (names[i][m] != '\0')
                    {
                        abbr[k++] = names[i][m++];
                    }
                    // Stop searching
                    break;
                }
            }
        }
        abbr[k] = '\0';
        printf("%s\n", abbr);
    }

    return 0;
}

