            return;
        }
    }
    printf("Book not found.\n");
}

void sort_by_acc(struct library *lib, int count)
{
    struct library temp;
    int i, j;
    for (i = 0; i < count - 1; i++)
    {
        for (j = 0; j < count - i - 1; j++)
        {
            if (lib[j].acc_no > lib[j + 1].acc_no)
            {
                temp = lib[j];
                lib[j] = lib[j + 1];
                lib[j + 1] = temp;
            }
        }
    }
}

