void charCounter(char str[], int *vowelCount, int *consonantCount)
{
    int tempVowelCount = 0, tempConsonantCount = 0;
    while (*str != '\0')
    {
        char ch = tolower(*str);
        if (isalpha(ch))
        {
            if (ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u')
            {
                tempVowelCount++;
            }
            else
            {
                tempConsonantCount++;
            }
        }
        str++;
    }

    *vowelCount = tempVowelCount;
    *consonantCount = tempConsonantCount;
}

