void str_rev(char str[])
{
    int i, j;
    char temp;
    i = 0;
    j = strlen(str) - 1; // not taking the null
    while (i < j)
    {
        temp = str[i];
        str[i] = str[j];
        str[j] = temp;
        i++;
        j--;
    }
}

