void _short_1(char str[])
{
    int i = 0, j = 0;
    char s[10];
    if (str[0] != '\0' && str[0] != ' ')
    {
        s[j] = toupper(str[j]);
        i++;
        j++;
    }
    while (str[i] != '\0')
    {
        if (str[i] == ' ')
        {
            s[j] = toupper(str[i + 1]);
            i++;
            j++;
        }
        i++;
    }
    s[j] = '\0';
    printf("\nResult 1: %s", s);
}

void _short_2(char str[])
{
    int i, j;
    char strnew[10];
    strnew[0] = toupper(str[0]);
    i = j = 1;
    while (str[i] != '\0')
    {
        if (str[i] == ' ')
        {
            strnew[j++] = toupper(str[i + 1]);
        }
        i++;
    }
    strnew[j] = '\0';
    printf("\nResult 2: %s", strnew);
}

